{
  "sentences": [
    {
      "text": "我最近很忙，你呢？",
      "pinyin": "Wǒ zuìjìn hěn máng, nǐ ne?",
      "pinyin_numeric": "wo3 zui4jin4 hen3 mang2, ni3 ne0",
      "translation_en": "I've been very busy lately, and you?",
      "translation_ko": "저는 요즘 매우 바쁜데, 당신은요?"
    },
    {
      "text": "我週末打算去台北，你呢？",
      "pinyin": "Wǒ zhōumò dǎsuàn qù Táiběi, nǐ ne?",
      "pinyin_numeric": "wo3 zhou1mo4 da3suan4 qu4 Tai2bei3, ni3 ne0",
      "translation_en": "I plan to go to Taipei this weekend, and you?",
      "translation_ko": "저는 주말에 타이베이에 갈 계획인데, 당신은요?"
    },
    {
      "text": "我喜歡看電影，你呢？",
      "pinyin": "Wǒ xǐhuān kàn diànyǐng, nǐ ne?",
      "pinyin_numeric": "wo3 xi3huan1 kan4 dian4ying3, ni3 ne0",
      "translation_en": "I like watching movies, and you?",
      "translation_ko": "저는 영화 보는 것을 좋아하는데, 당신은요?"
    },
    {
      "text": "我對台灣小吃很有興趣，你呢？",
      "pinyin": "Wǒ duì Táiwān xiǎochī hěn yǒu xìngqù, nǐ ne?",
      "pinyin_numeric": "wo3 dui4 Tai2wan1 xiao3chi1 hen3 you3 xing4qu4, ni3 ne0",
      "translation_en": "I'm very interested in Taiwanese snacks, and you?",
      "translation_ko": "저는 대만 길거리 음식에 관심이 많은데, 당신은요?"
    },
    {
      "text": "我放假的時候喜歡去旅行，你呢？",
      "pinyin": "Wǒ fàngjià de shíhou xǐhuān qù lǚxíng, nǐ ne?",
      "pinyin_numeric": "wo3 fang4jia4 de0 shi2hou0 xi3huan1 qu4 lü3xing2, ni3 ne0",
      "translation_en": "I like to travel when I'm on vacation, and you?",
      "translation_ko": "저는 휴가 때 여행 가는 것을 좋아하는데, 당신은요?"
    },
    {
      "text": "我最近在學中文，你呢？",
      "pinyin": "Wǒ zuìjìn zài xué Zhōngwén, nǐ ne?",
      "pinyin_numeric": "wo3 zui4jin4 zai4 xue2 Zhong1wen2, ni3 ne0",
      "translation_en": "I've been learning Chinese recently, and you?",
      "translation_ko": "저는 요즘 중국어를 배우고 있는데, 당신은요?"
    },
    {
      "text": "我覺得這個夜市很熱鬧，你呢？",
      "pinyin": "Wǒ juéde zhège yèshì hěn rènào, nǐ ne?",
      "pinyin_numeric": "wo3 jue2de0 zhe4ge0 ye4shi4 hen3 re4nao4, ni3 ne0",
      "translation_en": "I think this night market is very lively, and you?",
      "translation_ko": "저는 이 야시장이 매우 활기차다고 생각하는데, 당신은요?"
    },
    {
      "text": "我明天有空，你呢？",
      "pinyin": "Wǒ míngtiān yǒu kòng, nǐ ne?",
      "pinyin_numeric": "wo3 ming2tian1 you3 kong4, ni3 ne0",
      "translation_en": "I'm free tomorrow, and you?",
      "translation_ko": "저는 내일 시간이 있는데, 당신은요?"
    },
    {
      "text": "我喜歡吃牛肉麵，你呢？",
      "pinyin": "Wǒ xǐhuān chī niúròumiàn, nǐ ne?",
      "pinyin_numeric": "wo3 xi3huan1 chi1 niu2rou4mian4, ni3 ne0",
      "translation_en": "I like eating beef noodles, and you?",
      "translation_ko": "저는 소고기 국수를 좋아하는데, 당신은요?"
    },
    {
      "text": "我最近在找新的工作，你呢？",
      "pinyin": "Wǒ zuìjìn zài zhǎo xīn de gōngzuò, nǐ ne?",
      "pinyin_numeric": "wo3 zui4jin4 zai4 zhao3 xin1 de0 gong1zuo4, ni3 ne0",
      "translation_en": "I've been looking for a new job recently, and you?",
      "translation_ko": "저는 요즘 새 일자리를 찾고 있는데, 당신은요?"
    }
  ]
}
